elements.algorithm-2411-002:
\caption{TE measure estimation.} \label{alg:te_est} Input: Training dataset $ ({i}^1, {y}^1, {i}^2, {y}^2... {i}^T, {y}^T) $, and feature of interest ${X}_i$. Output: $H({Y}|{\mathcal{X}}_{ ackslash {X}_i}) - H({Y}|{\mathcal{X}})$  egin{algorithmic}[1] \STATE Initialize weights for $	heta$ and $	heta_{ ackslash {X}_i}$ \FOR{$1$ to $N$} \STATE Draw mini batch samples of length $b$ from the joint distribution of the target and the network features with all possible variables included $ p_{Y,\mathcal{X}} \sim (y^{t_1},x^{t_1}_1,x^{t_1}_i \dots x^{t_1}_N),\dots,(y^{t_b},x^{t_b}_1,x^{t_b}_i \dots x^{t_b}_N)$, and repeat for the marginal distribution $p_{Y}\otimes p_{\mathcal{X}} \sim (y^{t'_1},x^{t_1}_1,x^{t_1}_i \dots x^{t_1}_N),\dots,(y^{t'_b},x^{t_b}_1,x^{t_b}_i \dots x^{t_b}_N)$, where $t'_i 
eq t_i$. \STATE Draw mini batch samples of length $b$ from the joint distribution of the target and the network features with variable $X_i$ missing. $ p_{Y,\mathcal{X}_{ ackslash X_i}} \sim (y^{t_1},x^{t_1}_1 \dots x^{t_1}_N),\dots,(y^{t_b},x^{t_b}_1 \dots x^{t_b}_N)$, and repeat for the marginal distribution $p_{Y}\otimes p_{\mathcal{X}_{ ackslash X_i}} \sim (y^{t'_1},x^{t_1}_1, \dots x^{t_1}_N),\dots,(y^{t'_b},x^{t_b}_1 \dots x^{t_b}_N)$, where $t'_i 
eq t_i$. \STATE $I({Y};{\mathcal{X}}) \geq  rac{1}{b}\sum^b_{j=1}F_{	heta}(y^{t_j},x^{t_j}_1,x^{t_j}_i \dots x^{t_j}_N)) -  rac{1}{b}\sum^b_{j=1}\log{e^{F_{	heta}((y^{t_j'}_1,x^{t_j}_1,x^{t_j}_i \dots x^{t_j}_N)}}$ \STATE $I({Y};{\mathcal{X}}_{ ackslash {X}_i}) \geq  rac{1}{b}\sum^b_{j=1}F_{	heta_{ ackslash {X}_i}}((y^{t_j},x^{t_j}_1 \dots x^{t_j}_N)) -  rac{1}{b}\sum^b_{j=1}\log{e^{F_{	heta_{ ackslash {X}_i}}(y^{t_j'}_1,x^{t_j}_1 \dots x^{t_j}_N)}}$ \STATE $	heta \leftarrow 	ilde{
abla}_{	heta} I({Y};{\mathcal{X}})$ \STATE $	heta_{ ackslash {X}_i} \leftarrow 	ilde{
abla}_{	heta_{ ackslash {X}_i}} I({Y};{\mathcal{X}}_{ ackslash {X}_i})$ \ENDFOR \STATE return $I({Y};{\mathcal{X}}) - I({Y};{\mathcal{X}}_{ ackslash {X}_i})$ \end{algorithmic} \caption{Estimation of $\Phi_{{X}_i;{\mathcal{X}} ightarrow {Y}}$. } \label{alg:estimation}

